import React, { useRef } from 'react';
import { SPECIAL_TAGS } from '../constants';
import { Smile, Frown, Megaphone, PauseCircle } from 'lucide-react';
import { TagType } from '../types';

interface TextInputProps {
  value: string;
  onChange: (val: string) => void;
  disabled: boolean;
}

const ICONS: Record<string, React.ReactNode> = {
  pause: <PauseCircle size={14} />,
  smile: <Smile size={14} />,
  megaphone: <Megaphone size={14} />,
  frown: <Frown size={14} />,
};

export const TextInput: React.FC<TextInputProps> = ({ value, onChange, disabled }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const insertTag = (tag: string) => {
    if (!textareaRef.current) return;

    const start = textareaRef.current.selectionStart;
    const end = textareaRef.current.selectionEnd;
    const text = textareaRef.current.value;

    const newText = text.substring(0, start) + " " + tag + " " + text.substring(end);
    onChange(newText);

    // Defer focus back to textarea
    setTimeout(() => {
      textareaRef.current?.focus();
      const newCursorPos = start + tag.length + 2;
      textareaRef.current?.setSelectionRange(newCursorPos, newCursorPos);
    }, 0);
  };

  return (
    <div className="space-y-3">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <label className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
          7. Contenido
        </label>
        <div className="flex gap-2 flex-wrap">
          {SPECIAL_TAGS.map((t) => (
            <button
              key={t.tag}
              onClick={() => insertTag(t.tag)}
              disabled={disabled}
              className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-700 hover:bg-slate-600 text-slate-200 text-xs rounded-full transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              title={`Insertar ${t.label}`}
            >
              {ICONS[t.icon]}
              {t.label}
            </button>
          ))}
        </div>
      </div>

      <textarea
        ref={textareaRef}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        disabled={disabled}
        placeholder="Escribe aquí el texto que quieres convertir a voz..."
        className="w-full h-40 bg-slate-800 border-2 border-slate-700 rounded-xl p-4 text-slate-100 placeholder-slate-500 focus:border-indigo-500 focus:ring-0 outline-none resize-none transition-colors"
      />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { HistoryItem } from '../types';
import { Play, Pause, Download, Trash2, Clock, Music } from 'lucide-react';
import { createWavBlob } from '../utils/audioUtils';

interface HistoryProps {
  items: HistoryItem[];
  onDelete: (id: string) => void;
}

export const History: React.FC<HistoryProps> = ({ items, onDelete }) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Cleanup audio on unmount
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  const handlePlay = (item: HistoryItem) => {
    if (playingId === item.id) {
      audioRef.current?.pause();
      setPlayingId(null);
      return;
    }

    if (audioRef.current) {
      audioRef.current.pause();
    }

    const url = URL.createObjectURL(item.audioBlob);
    const audio = new Audio(url);
    audioRef.current = audio;

    audio.onended = () => {
      setPlayingId(null);
      URL.revokeObjectURL(url);
    };

    audio.play();
    setPlayingId(item.id);
  };

  const handleDownload = (item: HistoryItem) => {
    const url = URL.createObjectURL(item.audioBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `gemini-tts-${item.timestamp}.wav`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (items.length === 0) {
    return (
      <div className="text-center py-12 border-2 border-dashed border-slate-800 rounded-xl">
        <Music className="mx-auto h-12 w-12 text-slate-600 mb-3" />
        <h3 className="text-slate-400 font-medium">Sin historial</h3>
        <p className="text-slate-600 text-sm">Genera tu primer audio para verlo aquí</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {items.map((item) => (
        <div 
          key={item.id} 
          className="bg-slate-800 rounded-xl p-4 flex items-center gap-4 border border-slate-700 hover:border-slate-600 transition-colors"
        >
          <button
            onClick={() => handlePlay(item)}
            className="flex-shrink-0 w-12 h-12 rounded-full bg-indigo-600 hover:bg-indigo-500 flex items-center justify-center text-white transition-colors"
          >
            {playingId === item.id ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-0.5" />}
          </button>

          <div className="flex-grow min-w-0">
            <p className="text-sm text-slate-200 truncate font-medium pr-4">
              {item.text}
            </p>
            <div className="flex items-center gap-3 text-xs text-slate-500 mt-1">
              <span className="flex items-center gap-1">
                <Clock size={12} />
                {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
              <span className="bg-slate-700 px-1.5 py-0.5 rounded text-slate-300">
                {item.settings.voiceName}
              </span>
              <span className="bg-slate-700 px-1.5 py-0.5 rounded text-slate-300 capitalize">
                {item.settings.style}
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => handleDownload(item)}
              className="p-2 text-slate-400 hover:text-indigo-400 hover:bg-slate-700 rounded-lg transition-colors"
              title="Descargar"
            >
              <Download size={18} />
            </button>
            <button
              onClick={() => onDelete(item.id)}
              className="p-2 text-slate-400 hover:text-red-400 hover:bg-slate-700 rounded-lg transition-colors"
              title="Eliminar"
            >
              <Trash2 size={18} />
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

