import { GoogleGenAI, Modality, Type } from "@google/genai";
import { GenerationSettings, VoiceOption } from "../types";
import { VOICES, STYLES, ACCENTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateSpeech(
  text: string,
  settings: GenerationSettings
): Promise<string> {
  const voice = VOICES.find((v) => v.id === settings.voiceId) || VOICES[0];

  // Construct a prompt that guides the model on HOW to speak the text
  let speedDesc = "normal";
  if (settings.speed < 0.8) speedDesc = "muy lenta";
  else if (settings.speed < 1.0) speedDesc = "lenta";
  else if (settings.speed > 1.5) speedDesc = "muy rápida";
  else if (settings.speed > 1.0) speedDesc = "rápida";

  let pitchDesc = "normal";
  if (settings.pitch < -5) pitchDesc = "muy grave y profundo";
  else if (settings.pitch < 0) pitchDesc = "grave";
  else if (settings.pitch > 5) pitchDesc = "muy agudo";
  else if (settings.pitch > 0) pitchDesc = "agudo";

  const prompt = `
    Por favor, lee el siguiente texto en voz alta.

    Instrucciones de Dirección de Voz:
    - Idioma: Español (${settings.accent})
    - Estilo: ${settings.style}
    - Velocidad: ${speedDesc}
    - Tono: ${pitchDesc}

    Instrucciones de Etiquetas Especiales en el texto:
    - [pausa]: Haz una pausa de silencio de 2 segundos.
    - [risa]: Inserta una risa natural donde corresponda.
    - [grito]: Lee la frase con voz enérgica, fuerte y exclamativa.
    - [llanto]: Simula un breve llanto o voz quebrada.

    Texto a leer:
    "${text}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: {
              voiceName: voice.apiVoiceName,
            },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
      throw new Error("No audio data returned from Gemini.");
    }

    return base64Audio;
  } catch (error) {
    console.error("Gemini TTS Error:", error);
    throw error;
  }
}

export interface VoiceAnalysisResult {
  gender: 'male' | 'female';
  pitch: number;
  speed: number;
  style: string;
  accent: string;
}

export async function analyzeVoiceSample(base64Audio: string): Promise<VoiceAnalysisResult> {
  // We use the standard flash model for multimodal analysis
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: {
      parts: [
        { inlineData: { mimeType: 'audio/mp3', data: base64Audio } }, // Assuming generic audio, model handles most
        { text: `
          Analyze this voice sample and extract the following parameters to reproduce it:
          1. Gender (male or female)
          2. Pitch (scale from -10 to 10, where -10 is very deep/low, 0 is normal, 10 is very high/squeaky)
          3. Speed (scale from 0.5 to 2.0, where 1.0 is normal conversation speed)
          4. Style (choose closest one: 'natural', 'cheerful', 'sad', 'whisper', 'storyteller')
          5. Accent (choose closest one: 'España', 'México', 'Argentina')
        ` }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          gender: { type: Type.STRING, enum: ['male', 'female'] },
          pitch: { type: Type.NUMBER },
          speed: { type: Type.NUMBER },
          style: { type: Type.STRING, enum: STYLES.map(s => s.id) },
          accent: { type: Type.STRING, enum: ACCENTS.map(a => a.label) }
        },
        required: ['gender', 'pitch', 'speed', 'style', 'accent']
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Could not analyze voice sample");

  return JSON.parse(text) as VoiceAnalysisResult;
}

