  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: {
              voiceName: voice.apiVoiceName,
            },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
      throw new Error("No audio data returned from Gemini.");
    }

    return base64Audio;
  } catch (error) {
    console.error("Gemini TTS Error:", error);
    throw error;
  }
}

export interface VoiceAnalysisResult {
  gender: 'male' | 'female';
  pitch: number;
  speed: number;
  style: string;
  accent: string;
}

export async function analyzeVoiceSample(base64Audio: string): Promise<VoiceAnalysisResult> {
  // We use the standard flash model for multimodal analysis
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: {
      parts: [
        { inlineData: { mimeType: 'audio/mp3', data: base64Audio } }, // Assuming generic audio, model handles most
        { text: `
          Analyze this voice sample and extract the following parameters to reproduce it:
          1. Gender (male or female)
          2. Pitch (scale from -10 to 10, where -10 is very deep/low, 0 is normal, 10 is very high/squeaky)
          3. Speed (scale from 0.5 to 2.0, where 1.0 is normal conversation speed)
          4. Style (choose closest one: 'natural', 'cheerful', 'sad', 'whisper', 'storyteller')
          5. Accent (choose closest one: 'España', 'México', 'Argentina')
        ` }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          gender: { type: Type.STRING, enum: ['male', 'female'] },
          pitch: { type: Type.NUMBER },
          speed: { type: Type.NUMBER },
          style: { type: Type.STRING, enum: STYLES.map(s => s.id) },
          accent: { type: Type.STRING, enum: ACCENTS.map(a => a.label) }
        },
        required: ['gender', 'pitch', 'speed', 'style', 'accent']
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Could not analyze voice sample");

  return JSON.parse(text) as VoiceAnalysisResult;
}

import React, { useRef } from 'react';
import { VoiceOption } from '../types';
import { User, Mic, Upload, Sparkles, Check } from 'lucide-react';
import { VOICES } from '../constants';

interface VoiceSelectorProps {
  selectedVoiceId: string;
  onSelect: (id: string) => void;
  onImport: (file: File) => void;
  isAnalyzing: boolean;
  detectedGender: 'male' | 'female' | null;
}

export const VoiceSelector: React.FC<VoiceSelectorProps> = ({ 
  selectedVoiceId, 
  onSelect, 
  onImport,
  isAnalyzing,
  detectedGender
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onImport(e.target.files[0]);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const males = VOICES.filter(v => v.gender === 'male');
  const females = VOICES.filter(v => v.gender === 'female');

  const renderVoiceGrid = (voices: VoiceOption[]) => (
    <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
      {voices.map((voice) => {
        const isSelected = selectedVoiceId === voice.id;
        return (
          <button
            key={voice.id}
            onClick={() => onSelect(voice.id)}
            className={`
              relative flex flex-col items-center justify-center p-3 rounded-xl border transition-all duration-200
              ${isSelected 
                ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/30 transform scale-105 z-10' 
                : 'bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-750 hover:border-slate-600'
              }
            `}
          >
            <div className={`mb-2 p-2 rounded-full ${isSelected ? 'bg-indigo-500' : 'bg-slate-700'}`}>
              {voice.gender === 'male' ? <User size={20} /> : <Mic size={20} />}
            </div>
            <span className="text-xs font-medium text-center">{voice.name}</span>
          </button>
        );
      })}
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <label className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
          1. Seleccionar Voz
        </label>
        <div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="audio/*" 
            className="hidden" 
          />
          <button
            onClick={() => fileInputRef.current?.click()}
            disabled={isAnalyzing}
            className="flex items-center gap-2 text-xs bg-indigo-500/10 hover:bg-indigo-500/20 text-indigo-300 border border-indigo-500/30 px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-wait"
            title="Sube un audio para imitar su estilo"
          >
            {isAnalyzing ? (
              <Sparkles className="animate-spin" size={14} />
            ) : (
              <Upload size={14} />
            )}
            {isAnalyzing ? "Analizando..." : "Importar Muestra"}
          </button>
        </div>
      </div>

      {/* Sección Hombres */}
      <div className={`space-y-3 p-4 rounded-2xl border transition-colors ${detectedGender === 'male' ? 'bg-indigo-900/20 border-indigo-500/50' : 'border-transparent'}`}>
        <h3 className="text-xs font-bold text-sky-400 uppercase flex items-center gap-2">
          <User size={16} /> 
          Voces Masculinas
          {detectedGender === 'male' && (
            <span className="ml-auto flex items-center gap-1 bg-indigo-500 text-white px-2 py-0.5 rounded-full text-[10px] animate-pulse">
              <Check size={10} /> Muestra Detectada
            </span>
          )}
        </h3>
        {renderVoiceGrid(males)}
      </div>

      {/* Sección Mujeres */}
      <div className={`space-y-3 p-4 rounded-2xl border transition-colors ${detectedGender === 'female' ? 'bg-pink-900/20 border-pink-500/50' : 'border-transparent'}`}>
        <h3 className="text-xs font-bold text-pink-400 uppercase flex items-center gap-2">
          <Mic size={16} /> 
          Voces Femeninas
          {detectedGender === 'female' && (
            <span className="ml-auto flex items-center gap-1 bg-pink-500 text-white px-2 py-0.5 rounded-full text-[10px] animate-pulse">
              <Check size={10} /> Muestra Detectada
            </span>
          )}
        </h3>
        {renderVoiceGrid(females)}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { VoiceSelector } from './components/VoiceSelector';
import { Controls } from './components/Controls';
import { TextInput } from './components/TextInput';
import { History } from './components/History';
import { GenerationSettings, HistoryItem } from './types';
import { VOICES } from './constants';
import { generateSpeech, analyzeVoiceSample } from './services/geminiService';
import { decodeBase64, decodeAudioData, createWavBlob } from './utils/audioUtils';
import { AudioWaveform, Wand2, Loader2, Sparkles, AlertCircle, CheckCircle } from 'lucide-react';

const App: React.FC = () => {
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [importStatus, setImportStatus] = useState<{msg: string, type: 'success' | 'error'} | null>(null);
  const [detectedGender, setDetectedGender] = useState<'male' | 'female' | null>(null);

  const [settings, setSettings] = useState<GenerationSettings>({
    voiceId: VOICES[0].id,
    accent: 'España',
    style: 'natural',
    speed: 1.0,
    pitch: 0,
  });
  const [history, setHistory] = useState<HistoryItem[]>([]);

  const handleGenerate = async () => {
    if (!text.trim()) return;

    setLoading(true);
    setImportStatus(null);
    try {
      // 1. Get Base64 Audio from Gemini
      const base64Audio = await generateSpeech(text, settings);

      // 2. Decode for local playback/storage
      const audioBytes = decodeBase64(base64Audio);
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(audioBytes, audioContext);

      // 3. Convert to WAV Blob for download/play
      const channelData = audioBuffer.getChannelData(0);
      const wavBlob = createWavBlob(channelData, 24000);

      const selectedVoice = VOICES.find(v => v.id === settings.voiceId);

      const newItem: HistoryItem = {
        id: crypto.randomUUID(),
        text: text,
        timestamp: Date.now(),
        audioBlob: wavBlob,
        duration: audioBuffer.duration,
        settings: {
          voiceName: selectedVoice?.name || 'Desconocido',
          style: settings.style,
        },
      };

      setHistory((prev) => [newItem, ...prev]);

      // Auto-play the result
      const audioUrl = URL.createObjectURL(wavBlob);
      const audio = new Audio(audioUrl);
      audio.play();

    } catch (error) {
      console.error('Generation failed:', error);
      alert('Error generando audio. Verifica tu API Key y conexión.');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteHistory = (id: string) => {
    setHistory((prev) => prev.filter((item) => item.id !== id));
  };

  const handleVoiceImport = async (file: File) => {
    setAnalyzing(true);
    setImportStatus(null);
    setDetectedGender(null);

    try {
      // Convert file to base64
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = async () => {
        try {
          const base64Result = reader.result as string;
          // Remove data:audio/xxx;base64, prefix
          const base64Data = base64Result.split(',')[1];

          const analysis = await analyzeVoiceSample(base64Data);

          // Find best matching voice ID based on gender
          const matchingVoices = VOICES.filter(v => v.gender === analysis.gender);
          const bestVoice = matchingVoices.length > 0 ? matchingVoices[0] : VOICES[0];

          setDetectedGender(analysis.gender);

          setSettings({
            voiceId: bestVoice.id,
            accent: analysis.accent,
            style: analysis.style,
            speed: analysis.speed,
            pitch: analysis.pitch
          });

          setImportStatus({
            msg: `Análisis completado: Se detectó voz ${analysis.gender === 'male' ? 'MASCULINA' : 'FEMENINA'}. Se seleccionó '${bestVoice.name}' con estilo '${analysis.style}'.`,
            type: 'success'
          });
        } catch (err) {
          console.error(err);
          setImportStatus({
            msg: "No se pudo analizar el audio. Intenta con otro archivo más claro.",
            type: 'error'
          });
        } finally {
          setAnalyzing(false);
        }
      };
    } catch (error) {
      console.error(error);
      setAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="sticky top-0 z-10 bg-slate-900/90 backdrop-blur-md border-b border-slate-800">
        <div className="max-w-5xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <AudioWaveform className="text-white" size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
                Voces Gemini
              </h1>
              <p className="text-xs text-indigo-400 font-medium tracking-wide">TTS ESPAÑOL</p>
            </div>
          </div>
          <div className="text-xs text-slate-500 hidden sm:block">
            Powered by gemini-2.5-flash-preview-tts
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 py-8 space-y-8">

        {/* Top Section: Settings & Input */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Settings */}
          <div className="lg:col-span-7 space-y-8">
            <section className="bg-slate-800/30 p-6 rounded-2xl border border-slate-800 space-y-6">
              <VoiceSelector 
                selectedVoiceId={settings.voiceId} 
                onSelect={(id) => {
                  setSettings(s => ({ ...s, voiceId: id }));
                  // If user manually selects a voice, we clear the "Detected" highlight to avoid confusion
                  if (detectedGender) {
                    const voice = VOICES.find(v => v.id === id);
                    if (voice && voice.gender !== detectedGender) {
                       setDetectedGender(null);
                    }
                  }
                }}
                onImport={handleVoiceImport}
                isAnalyzing={analyzing}
                detectedGender={detectedGender}
              />

              {importStatus && (
                <div className={`text-sm p-3 rounded-lg flex items-start gap-2 ${
                  importStatus.type === 'success' ? 'bg-emerald-500/10 text-emerald-300 border border-emerald-500/20' : 'bg-red-500/10 text-red-300 border border-red-500/20'
                }`}>
                   {importStatus.type === 'success' ? <CheckCircle size={16} className="mt-0.5" /> : <AlertCircle size={16} className="mt-0.5" />}
                   {importStatus.msg}
                </div>
              )}

              <Controls 
                settings={settings} 
                onChange={setSettings} 
              />
            </section>
          </div>

          {/* Right Column: Input & Action */}
          <div className="lg:col-span-5 flex flex-col gap-6">
            <section className="bg-slate-800/30 p-6 rounded-2xl border border-slate-800 flex-grow">
              <TextInput 
                value={text} 
                onChange={setText} 
                disabled={loading} 
              />

              <div className="mt-6">
                <button
                  onClick={handleGenerate}
                  disabled={loading || !text.trim()}
                  className="w-full relative group overflow-hidden bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-700 disabled:cursor-not-allowed text-white font-bold py-4 px-6 rounded-xl transition-all shadow-lg shadow-indigo-900/40"
                >
                  <span className="relative z-10 flex items-center justify-center gap-2">
                    {loading ? (
                      <>
                        <Loader2 className="animate-spin" /> Generando...
                      </>
                    ) : (
                      <>
                        <Wand2 className="group-hover:rotate-12 transition-transform" />
                        Generar Audio
                      </>
                    )}
                  </span>
                  {!loading && (
                    <div className="absolute inset-0 bg-gradient-to-r from-indigo-500 to-purple-600 opacity-0 group-hover:opacity-100 transition-opacity" />
                  )}
                </button>
                <p className="text-center text-xs text-slate-500 mt-3">
                  Usa <span className="text-indigo-400 font-mono">[etiquetas]</span> para efectos especiales
                </p>
              </div>
            </section>
          </div>
        </div>

        {/* Bottom Section: History */}
        <div className="border-t border-slate-800 pt-8">
          <div className="flex items-center gap-2 mb-6">
            <Sparkles className="text-indigo-400" size={20} />
            <h2 className="text-lg font-bold text-white">6. Historial de Generación</h2>
          </div>
          <History items={history} onDelete={handleDeleteHistory} />
        </div>

      </main>

      <footer className="max-w-5xl mx-auto px-4 py-8 text-center text-slate-600 text-sm">
        <p>Voces Gemini TTS &copy; {new Date().getFullYear()}</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Modality, Type } from "@google/genai";
import { GenerationSettings, VoiceOption } from "../types";
import { VOICES, STYLES, ACCENTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateSpeech(
  text: string,
  settings: GenerationSettings
): Promise<string> {
  const voice = VOICES.find((v) => v.id === settings.voiceId) || VOICES[0];
  const accentDetail = ACCENTS.find((a) => a.label === settings.accent) || ACCENTS[0];

  // Construct a prompt that guides the model on HOW to speak the text
  let speedDesc = "normal";
  if (settings.speed < 0.8) speedDesc = "muy lenta";
  else if (settings.speed < 1.0) speedDesc = "lenta";
  else if (settings.speed > 1.5) speedDesc = "muy rápida";
  else if (settings.speed > 1.0) speedDesc = "rápida";

  let pitchDesc = "normal";
  if (settings.pitch < -5) pitchDesc = "muy grave y profundo";
  else if (settings.pitch < 0) pitchDesc = "grave";
  else if (settings.pitch > 5) pitchDesc = "muy agudo";
  else if (settings.pitch > 0) pitchDesc = "agudo";

  const prompt = `
    Por favor, lee el siguiente texto en voz alta. 
    Es CRÍTICO que utilices un acento español de España, específicamente de la zona centro (Castilla).

    Instrucciones de Dirección de Voz Regional:
    - Región Específica: ${settings.accent}.
    - Detalle de Acento: ${accentDetail.description}
    - Estilo: ${settings.style}
    - Velocidad: ${speedDesc}
    - Tono: ${pitchDesc}

    Instrucciones de Etiquetas Especiales:
    - [pausa]: Silencio de 2 segundos.
    - [risa]: Inserta una risa natural.
    - [grito]: Voz enérgica y exclamativa.
    - [llanto]: Voz quebrada.
    - [susurro]: Voz baja y sibilante.
    - [aplausos]: Sonido de ambiente de aplausos.

    Texto a leer:
    "${text}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: {
              voiceName: voice.apiVoiceName,
            },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
      throw new Error("No audio data returned from Gemini.");
    }

    return base64Audio;
  } catch (error) {
    console.error("Gemini TTS Error:", error);
    throw error;
  }
}

